// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#define MAXN 2000
#define MAXM 2000
int n, m;
int grid[MAXN][MAXM];
int visited[MAXN][MAXM];
int max_size = 0;
void bfs(int x, int y, int type1, int type2) {
    int queue[MAXN*MAXM][2];
    int front = 0, rear = 0;
    queue[rear][0] = x;
    queue[rear++][1] = y;
    visited[x][y] = 1;
    int size = 0;
    while (front < rear) {
        int curr_x = queue[front][0];
        int curr_y = queue[front++][1];
        size++;
        if (grid[curr_x][curr_y] == type1 || grid[curr_x][curr_y] == type2) {
            if (curr_x > 0 && !visited[curr_x-1][curr_y] && (grid[curr_x-1][curr_y] == type1 || grid[curr_x-1][curr_y] == type2)) {
                queue[rear][0] = curr_x-1;
                queue[rear++][1] = curr_y;
                visited[curr_x-1][curr_y] = 1;
            }
            if (curr_x < n-1 && !visited[curr_x+1][curr_y] && (grid[curr_x+1][curr_y] == type1 || grid[curr_x+1][curr_y] == type2)) {
                queue[rear][0] = curr_x+1;
                queue[rear++][1] = curr_y;
                visited[curr_x+1][curr_y] = 1;
            }
            if (curr_y > 0 && !visited[curr_x][curr_y-1] && (grid[curr_x][curr_y-1] == type1 || grid[curr_x][curr_y-1] == type2)) {
                queue[rear][0] = curr_x;
                queue[rear++][1] = curr_y-1;
                visited[curr_x][curr_y-1] = 1;
            }
            if (curr_y < m-1 && !visited[curr_x][curr_y+1] && (grid[curr_x][curr_y+1] == type1 || grid[curr_x][curr_y+1] == type2)) {
                queue[rear][0] = curr_x;
                queue[rear++][1] = curr_y+1;
                visited[curr_x][curr_y+1] = 1;
            }
        }
    }
    max_size = (max_size > size) ? max_size : size;
}
int main() {
    scanf("%d %d", &n, &m);
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            scanf("%d", &grid[i][j]);
        }
    }
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            if (!visited[i][j]) {
                bfs(i, j, grid[i][j], -1);
            }
        }
    }
    printf("%d\n", max_size);
    return 0;
}

